  async updateAgent(req, res) {
    try {
      const { error, value } = updateAgentSchema.validate({
        ...req.params,
        ...req.body,
      });

      if (error) {
        return res.status(400).json({ error: error.details[0].message });
      }

      const {
        user_id,
        agent_id,
        conversation_config,
        name,
        platform_settings,
      } = value;

      // Check if agent belongs to user
      const userDoc = await db.collection("users").doc(user_id).get();
      if (!userDoc.exists) {
        return res.status(404).json({ error: "User not found" });
      }

      const userData = userDoc.data();
      const agentIndex = userData.agents?.findIndex(
        (agent) => agent.agent_id === agent_id,
      );

      if (agentIndex === -1) {
        return res.status(404).json({
          error: "Agent not found or does not belong to user",
        });
      }

      // --------- NEW: Update dynamic vars if agent transfers the call ---------
      const transferToAgentConfig =
        conversation_config?.agent?.prompt?.built_in_tools?.transfer_to_agent;

      if (transferToAgentConfig?.params?.transfers?.length) {
        const dynamicVariablePlaceholders =
          conversation_config.dynamic_variables?.dynamic_variable_placeholders || {};

        let updatedUserAgents = [...userData.agents];
        let isUserAgentsUpdated = false;

        for (const transfer of transferToAgentConfig.params.transfers) {
          const transferAgentId = transfer.agent_id;

          // Try to find the agent in current user's data
          let transferredAgent = updatedUserAgents.find(
            (agent) => agent.agent_id === transferAgentId,
          );

          let transferredPlaceholders =
            transferredAgent?.conversation_config?.agent?.dynamic_variables
              ?.dynamic_variable_placeholders;

          // If missing or undefined, fetch from ElevenLabs
          if (!transferredPlaceholders) {
            try {
              const agentDetails = await elevenLabsService.getAgent(transferAgentId);
              transferredPlaceholders =
                agentDetails?.conversation_config?.agent?.dynamic_variables
                  ?.dynamic_variable_placeholders;

              if (transferredPlaceholders) {
                // Update Firebase for future use
                const existingAgentIndex = updatedUserAgents.findIndex(
                  (a) => a.agent_id === transferAgentId,
                );

                if (existingAgentIndex !== -1) {
                  updatedUserAgents[existingAgentIndex] = {
                    ...updatedUserAgents[existingAgentIndex],
                    conversation_config: {
                      ...updatedUserAgents[existingAgentIndex].conversation_config,
                      agent: {
                        ...updatedUserAgents[existingAgentIndex].conversation_config?.agent,
                        dynamic_variables: {
                          ...updatedUserAgents[existingAgentIndex].conversation_config?.agent?.dynamic_variables,
                          dynamic_variable_placeholders: transferredPlaceholders,
                        },
                      },
                    },
                  };
                } else {
                  // If not present, add new entry
                  updatedUserAgents.push({
                    agent_id: transferAgentId,
                    name: agentDetails.name || "Unnamed",
                    conversation_config: agentDetails.conversation_config,
                  });
                }

                isUserAgentsUpdated = true;
              }
            } catch (err) {
              console.error(`Failed to fetch agent ${transferAgentId} from ElevenLabs`, err);
              continue;
            }
          }

          if (transferredPlaceholders) {
            for (const [key, value] of Object.entries(transferredPlaceholders)) {
              if (!(key in dynamicVariablePlaceholders)) {
                dynamicVariablePlaceholders[key] = value;
              }
            }
          }
        }
        console.log("Raw Dynamic Variables -> ",conversation_config.agent.dynamic_variables);

        // Assign merged dynamic variables back into payload
        // Make sure all paths exist
        conversation_config.agent = conversation_config.agent || {};
        conversation_config.agent.dynamic_variables = conversation_config.agent.dynamic_variables || {};
        conversation_config.agent.dynamic_variables.dynamic_variable_placeholders =
          conversation_config.agent.dynamic_variables.dynamic_variable_placeholders || {};

        // Merge: add only missing keys from new placeholders
        for (const [key, value] of Object.entries(dynamicVariablePlaceholders)) {
          if (!(key in conversation_config.agent.dynamic_variables.dynamic_variable_placeholders)) {
            conversation_config.agent.dynamic_variables.dynamic_variable_placeholders[key] = value;
          }
        }

        console.log("Updated Dynamic Variables -> ",conversation_config.agent.dynamic_variables);

        // Update Firebase if we pulled any new agent configs
        if (isUserAgentsUpdated) {
          await userDoc.ref.update({ agents: updatedUserAgents });
        }
      }

      // ------------------------------------------------------------------------

      // Update agent in Eleven Labs
      const updatedAgent = await elevenLabsService.updateAgent(
        agent_id,
        name,
        conversation_config || {},
        platform_settings,
      );

      // Update agent name in Firebase if provided
      if (name) {
        const updatedAgents = [...userData.agents];
        updatedAgents[agentIndex] = {
          ...updatedAgents[agentIndex],
          name: name,
        };
        await userDoc.ref.update({ agents: updatedAgents });
      }

      // Log agent update
      await auditService.logAgentAction(
        user_id,
        "updated",
        agent_id,
        `Updated agent "${name || "Unknown"}" with ID ${agent_id}`,
      );

      res.json(updatedAgent);
    } catch (error) {
      console.log("Error updating the agent:", error);
      res.status(500).json({ error: "Failed to update agent" });
    }
  },


  async deleteAgent(req, res) {
    try {
      const { error, value } = deleteAgentSchema.validate(req.params);
      if (error) {
        return res.status(400).json({ error: error.details[0].message });
      }

      const { user_id, agent_id } = req.params;

      // Check if agent belongs to user
      const userDoc = await db.collection("users").doc(user_id).get();
      if (!userDoc.exists) {
        return res.status(404).json({ error: "User not found" });
      }

      const userData = userDoc.data();
      const agentExists = userData.agents?.some(
        (agent) => agent.agent_id === agent_id,
      );
      if (!agentExists) {
        return res
          .status(404)
          .json({ error: "Agent not found or does not belong to user" });
      }

      // Delete agent from Eleven Labs
      await elevenLabsService.deleteAgent(agent_id);

      // Remove agent from user's agents list
      const updatedAgents = userData.agents.filter(
        (agent) => agent.agent_id !== agent_id,
      );
      await userDoc.ref.update({ agents: updatedAgents });

      // Log agent deletion
      await auditService.logAgentAction(
        user_id,
        "deleted",
        agent_id,
        `Deleted agent with ID ${agent_id}`,
      );

      res.status(204).send();
    } catch (error) {
      console.error("Error deleting agent:", error);
      res.status(500).json({ error: "Failed to delete agent" });
    }
  },

  async getAgent(req, res) {
    try {
      const { error, value } = getAgentSchema.validate(req.params);
      if (error) {
        return res.status(400).json({ error: error.details[0].message });
      }

      const { user_id, agent_id } = req.params;

      // Check if agent belongs to user
      const userDoc = await db.collection("users").doc(user_id).get();

      if (!userDoc.exists) {
        return res.status(404).json({ error: "User not found" });
      }

      const userData = userDoc.data();
      const agentExists = userData.agents?.some(
        (agent) => agent.agent_id === agent_id,
      );

      if (!agentExists) {
        return res
          .status(404)
          .json({ error: "Agent not found or does not belong to user" });
      }

      // Get agent details from Eleven Labs
      const agentDetails = await elevenLabsService.getAgent(agent_id);
      res.json(agentDetails);
    } catch (error) {
      console.error("Error getting agent:", error);
      res.status(500).json({ error: "Failed to get agent" });
    }
  },

  async listAgents(req, res) {
    try {
      const { error, value } = listAgentsSchema.validate(req.params);
      if (error) {
        return res.status(400).json({ error: error.details[0].message });
      }

      const { user_id } = req.params;

      // Get user's agents from Firebase
      const userDoc = await db.collection("users").doc(user_id).get();
      if (!userDoc.exists) {
        return res.status(404).json({ error: "User not found" });
      }

      const userData = userDoc.data();
      const userAgents = userData.agents || [];

      res.json({
        agents: userAgents,
        has_more: false,
        next_cursor: null,
      });
    } catch (error) {
      console.error("Error listing agents:", error);
      res.status(500).json({ error: "Failed to list agents" });
    }
  },
};

