import { db } from "../config/firebase.js";

export const auditController = {
  async getAuditLogs(req, res) {
    try {

      const {
        limit = 100,
        offset = 0,
        startDate,
        endDate,
        userEmail,
        action,
        userName,
      } = req.query;

      let query = db.collection("audit_logs").orderBy("timestamp", "desc");

      // Apply filters
      if (startDate) {
        query = query.where("timestamp", ">=", new Date(startDate));
      }
      if (endDate) {
        query = query.where("timestamp", "<=", new Date(endDate));
      }
      if (userEmail) {
        query = query.where("userEmail", "==", userEmail);
      }
      if (userName) {
        query = query.where("userName", "==", userName);
      }
      if (action) {
        query = query.where("action", "==", action);
      }

      query = query.limit(parseInt(limit)).offset(parseInt(offset));

      const snapshot = await query.get();
      const logs = snapshot.docs.map((doc) => ({
        id: doc.id,
        ...doc.data(),
        timestamp: doc.data().timestamp.toDate(),
      }));

      res.json({
        logs,
        total: snapshot.size,
        hasMore: snapshot.size === parseInt(limit),
      });
    } catch (error) {
      console.error("Error fetching audit logs:", error);
      res.status(500).json({ error: "Failed to fetch audit logs" });
    }
  },

  async getUserAuditLogs(req, res) {
    try {
      if (!req.user || req.user.role !== "admin") {
        return res.status(403).json({ error: "Admin access required" });
      }

      const { userEmail } = req.params;
      const { limit = 50 } = req.query;

      const snapshot = await db
        .collection("audit_logs")
        .where("userEmail", "==", userEmail)
        .orderBy("timestamp", "desc")
        .limit(parseInt(limit))
        .get();

      const logs = snapshot.docs.map((doc) => ({
        id: doc.id,
        ...doc.data(),
        timestamp: doc.data().timestamp.toDate(),
      }));

      res.json({ logs });
    } catch (error) {
      console.error("Error fetching user audit logs:", error);
      res.status(500).json({ error: "Failed to fetch user audit logs" });
    }
  },

  async getAuditStats(req, res) {
    try {
      if (!req.user || req.user.role !== "admin") {
        return res.status(403).json({ error: "Admin access required" });
      }

      const { days = 7 } = req.query;
      const startDate = new Date();
      startDate.setDate(startDate.getDate() - parseInt(days));

      const snapshot = await db
        .collection("audit_logs")
        .where("timestamp", ">=", startDate)
        .get();

      const stats = {
        totalLogs: snapshot.size,
        byAction: {},
        byUser: {},
      };

      snapshot.docs.forEach((doc) => {
        const data = doc.data();

        // Count by action
        stats.byAction[data.action] = (stats.byAction[data.action] || 0) + 1;

        // Count by user
        stats.byUser[data.userEmail] = (stats.byUser[data.userEmail] || 0) + 1;
      });

      res.json(stats);
    } catch (error) {
      console.error("Error fetching audit stats:", error);
      res.status(500).json({ error: "Failed to fetch audit stats" });
    }
  },
};

