export async function applyDefaultDynamicVars(agentId, clientVars = {}, elevenLabsService) {
  try {
    const agentDetails = await elevenLabsService.getAgent(agentId);

    const defaultVars =
      agentDetails?.conversation_config?.agent?.dynamic_variables?.dynamic_variable_placeholders || {};

    for (const [key, defaultVal] of Object.entries(defaultVars)) {
      const currentVal = clientVars[key];
      if (
        currentVal === undefined ||
        currentVal === null ||
        (typeof currentVal === "string" && currentVal.trim() === "")
      ) {
        clientVars[key] = defaultVal;
      }
    }

    return clientVars;
  } catch (err) {
    console.warn(`[DynamicVars] Could not fetch or apply defaults for agent (${agentId}):`, err.message);
    return clientVars; // Proceed with what exists
  }
}

